const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;
const FIRST_INSURANCE_MULTIPLIER = 1.1;

// Round up in MHPCO's favour, guarding against floating-point noise
// (e.g. 197.50000000001 should still round to 198, not 199).
const roundUpInMHPCOFavor = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

export const quote = (
  items: Item[],
  customer: Customer,
  contractIndex: number,
): number => {
  let policyBase = 0;
  for (const item of items) {
    policyBase += SWORD_BASE_PREMIUM * FIRST_INSURANCE_MULTIPLIER;
  }
  const total = policyBase + PROCESSING_FEE;
  return roundUpInMHPCOFavor(total);
};
